input.content:
interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  rune: 25,
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => {
    const base = step.items.reduce(
      (sum, item) => sum + BASE_PREMIUM[item.type],
      0,
    );
    const withFirstInsurance = base * 1.1;
    const premium = Math.ceil(withFirstInsurance + 5);
    return { premium };
  });
  return { results };
};

