interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

const BASE_PREMIUM: Record<string, number> = {
  rune: 25,
};

const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const PROCESSING_FEE = 5;
const ROUNDING_PRECISION = 6;

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => {
    const base = step.items.reduce(
      (sum, item) => sum + BASE_PREMIUM[item.type],
      0,
    );
    const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
    const premium = Math.ceil(
      Number((withFirstInsurance + PROCESSING_FEE).toFixed(ROUNDING_PRECISION)),
    );
    return { premium };
  });
  return { results };
};

