interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

const COMPONENT_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const PROCESSING_FEE = 5;
const ROUNDING_PRECISION = 6;

const componentBasePremium = (count: number): number => {
  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
  return count * COMPONENT_PREMIUM;
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => {
    const runeCount = step.items.filter((item) => item.type === "rune").length;
    const base = componentBasePremium(runeCount);
    const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
    const premium = Math.ceil(
      Number((withFirstInsurance + PROCESSING_FEE).toFixed(ROUNDING_PRECISION)),
    );
    return { premium };
  });
  return { results };
};

