interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Customer {
  yearsWithMHPCO: number;
}

interface Scenario {
  customer: Customer;
  steps: QuoteStep[];
}

const COMPONENT_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const PROCESSING_FEE = 5;
const ROUNDING_PRECISION = 6;

const componentBasePremium = (count: number): number => {
  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
  return count * COMPONENT_PREMIUM;
};

const COMPONENT_TYPES = ["rune", "moonstone"];

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const { type } of items) {
    if (COMPONENT_TYPES.includes(type)) {
      counts.set(type, (counts.get(type) ?? 0) + 1);
    }
  }
  return counts;
};

const componentsBasePremium = (items: Item[]): number => {
  const counts = [...countByType(items).values()];
  return counts.reduce((total, count) => total + componentBasePremium(count), 0);
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  const results = scenario.steps.map((step) => {
    const base = componentsBasePremium(step.items);
    const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
    const premium = Math.ceil(
      Number((withFirstInsurance + PROCESSING_FEE).toFixed(ROUNDING_PRECISION)),
    );
    return { premium };
  });
  return { results };
};

