import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Base premiums for single main items (base + 5 fee, newcomer: +10% first ins) ---
  // To isolate base premiums we use a long-standing customer's follow-up contract where
  // policy-wide modifiers are exercised separately; here we cover the raw base premium rule.

  // Edge case: empty item list
  it("empty item list → premium 5 (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result.results[0]).toEqual({ premium: 5 });
  });

  // Building block base premiums (components) — isolated base premium values
  it("2 runes → 50 G base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    // base 50 (2×25, no block) + 10% first insurance = 55, + 5 fee = 60
    expect(result.results[0]).toEqual({ premium: 60 });
  });
  it("3 runes → 60 G base premium (block applies)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    // block of 3 → base 60, +10% first insurance = 66, +5 fee = 71
    expect(result.results[0]).toEqual({ premium: 71 });
  });
  it("4 runes → 100 G base premium (no block — block requires exactly 3)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
          ],
        },
      ],
    });
    // no block (requires exactly 3) → base 100, +10% = 110, +5 = 115
    expect(result.results[0]).toEqual({ premium: 115 });
  });
  it("7 runes → 175 G base premium", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: Array.from({ length: 7 }, () => ({ type: "rune" })) },
      ],
    });
    // no block → base 175, +10% = 192.5, +5 = 197.5, round up = 198
    expect(result.results[0]).toEqual({ premium: 198 });
  });
  it("2 runes + 1 moonstone → 75 G base premium (no block: different types)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
        },
      ],
    });
    // 2 runes (no block) + 1 moonstone → base 75, +10% = 82.5, +5 = 87.5, up = 88
    expect(result.results[0]).toEqual({ premium: 88 });
  });
  it("3 runes + 3 moonstones → 120 G base premium (two separate blocks)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "rune" },
            { type: "rune" },
            { type: "rune" },
            { type: "moonstone" },
            { type: "moonstone" },
            { type: "moonstone" },
          ],
        },
      ],
    });
    // two blocks → base 60 + 60 = 120, +10% = 132, +5 = 137
    expect(result.results[0]).toEqual({ premium: 137 });
  });

  // Integration: premium modifiers stacking
  it("newcomer cursed sword (0 yrs, steel, ench 3) → premium 165", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: true }],
        },
      ],
    });
    // 100 base + 50 curse + 10 first insurance = 160, + 5 fee = 165
    expect(result.results[0]).toEqual({ premium: 165 });
  });
  it.todo("long-standing customer 2nd contract (3 yrs, cursed sword steel ench 7) → premium 160");

  // Modifier thresholds
  it.todo("customer with exactly 2 years → loyalty discount applies");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with exactly enchantment 5 → both curse and high-enchant surcharges apply");

  // Modifier scope on multi-item policies
  it.todo("cursed sword + plain amulet → 210 G before further modifiers and fee (curse on item base only)");

  // Rounding
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");

  // --- Claim processing ---

  // Standard reimbursement (no special clauses)
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("rune (value 250), damage 200 → payout 100 (full minus 100 deductible, no special clause)");

  // High enchantment clause
  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");

  // Dragon material clause
  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (full then deductible)");

  // Both clauses — 50% wins
  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");
  it.todo("dragon-material sword, exactly enchantment 8, damage 1000 → payout 400 (high-enchant applies, then deductible)");

  // Deductible per damage event
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");

  // Cap / insurance sum
  it.todo("policy covers sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 (block discount does not affect sum)");

  // Cap exhaustion across successive claims
  it.todo("sword (cap 2000), two claims of 1500 each → first payout 1400 remaining 600, second payout 600 remaining 0");

  // Multiple items of same type
  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
  it.todo("dragon attack damages both swords (two sword damages) → each treated as separate damage with own deductible");
  it.todo("more sword damages than swords insured → claim rejected (throws)");

  // CLI / error cases
  it.todo("quote with unknown item type (broomstick) → throws");
  it.todo("claim references item not in policy (amulet damaged, only sword insured) → throws");
  it.todo("claim references item with unknown type → throws");
  it.todo("claim damage amount negative (-200) → throws");
});

