const isHighEnchantment = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const itemSurcharge = (item: Item): number => {
  const base = itemBasePremium(item);
  const curse = item.cursed ? CURSE_SURCHARGE_RATE * base : 0;
  const highEnchant = isHighEnchantment(item)
    ? HIGH_ENCHANTMENT_SURCHARGE_RATE * base
    : 0;
  return curse + highEnchant;
};

const itemSurcharges = (items: Item[]): number =>
  items.reduce((total, item) => total + itemSurcharge(item), 0);

const quotePremium = (
  items: Item[],
  customer: Customer,
  isFollowUp: boolean,
): number => {
  const base = policyBasePremium(items);
  const firstInsurance = base * FIRST_INSURANCE_SURCHARGE_RATE;
  const loyalty =
    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
      ? base * LOYALTY_DISCOUNT_RATE
      : 0;
  const followUp = isFollowUp ? base * FOLLOWUP_DISCOUNT_RATE : 0;
  const total =
    base +
    itemSurcharges(items) +
    firstInsurance -
    loyalty -
    followUp +
    PROCESSING_FEE;
  return Math.ceil(Number(total.toFixed(ROUNDING_PRECISION)));
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => {
  let quoteCount = 0;
  const results = scenario.steps.map((step) => {
    const isFollowUp = quoteCount > 0;
    quoteCount += 1;
    const premium = quotePremium(step.items, scenario.customer, isFollowUp);
    return { premium };
  });
  return { results };
};

